  Purpose: one-time script to register Invoica on SAP. Run manually on server, not in CI.

  import { getSapClient } from '../src/lib/sap-client';

  async function main() {
    const sap = getSapClient();
    console.log('[SAP] Registering Invoica agent...');

    // Register using fluent builder
    const result = await sap.builder
      .agent('Invoica')
      .description('Financial OS for AI agents — x402 invoicing, settlement detection, and tax compliance across Base, Polygon, Arbitrum, and Solana. Pay-per-call at 0.003 USDC.')
      .addCapability('payment:invoice', { protocol: 'x402', version: '1.0', chains: ['base', 'polygon', 'arbitrum', 'solana'] })
      .addCapability('payment:settle', { protocol: 'x402', version: '1.0' })
      .addCapability('compliance:tax', { countries: 12, standard: 'VAT/GST' })
      .addProtocol('x402')
      .addProtocol('A2A')
      .register();

    console.log('[SAP] Registered. Agent PDA:', result.agentPda?.toBase58() ?? result);
    console.log('[SAP] Add to .env: SAP_AGENT_PDA=' + (result.agentPda?.toBase58() ?? 'check result above'));
  }

  main().catch(err => { console.error('[SAP] Registration failed:', err); process.exit(1); });

  NOTE: Adjust builder API to match actual SDK. If .builder is not the right path, check:
    - sap.agent.register({ name, description, capabilities, protocols })
